const text = items[0].json.text || '';

if (!text || text.trim().length < 50) {
  return [{ json: { error: 'Could not extract enough text from the rubric file. Please ensure the PDF contains readable text.' } }];
}

const prompt = `You are an academic rubric parser. Extract the structured rubric from this document.

Return ONLY valid JSON with this exact structure:
{
  "programme": "programme name or empty string",
  "module_name": "module/subject name",
  "nqf_level": null or number,
  "assessment_type": "Case Study" or "Essay" or "Assignment" etc,
  "total_marks": total marks as number,
  "questions": [
    {
      "number": 1,
      "title": "question title/description",
      "marks": marks allocated as number,
      "criteria": ["criterion 1", "criterion 2", ...]
    }
  ],
  "structure_notes": ["any important notes about the rubric structure"],
  "grading_scale": [
    {
      "label": "Distinction",
      "range": "75-100%",
      "criteria": {}
    }
  ]
}

Rules:
- Extract ALL questions/sections with their mark allocations
- Each question should have specific criteria that will be assessed
- total_marks should equal the sum of all question marks
- If grading scale/levels are provided, include them
- If the document doesn't look like a rubric, still extract what you can
- Return ONLY the JSON, no markdown, no explanation

Document text:
${text.substring(0, 15000)}`;

return [{ json: { prompt } }];

const response = items[0].json;
let text = response.text || response.output || '';

if (!text && response.candidates && response.candidates.length > 0) {
  const parts = response.candidates[0].content.parts;
  if (parts && parts.length > 0) text = parts[0].text;
}

if (!text) {
  return [{ json: { error: 'AI failed to parse the rubric. Please try a clearer PDF.' } }];
}

let jsonStr = text.trim();
if (jsonStr.startsWith('```')) {
  jsonStr = jsonStr.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
}

const firstBrace = jsonStr.indexOf('{');
if (firstBrace > 0) jsonStr = jsonStr.substring(firstBrace);
if (!jsonStr.endsWith('}')) {
  const lastBrace = jsonStr.lastIndexOf('}');
  if (lastBrace > 0) jsonStr = jsonStr.substring(0, lastBrace + 1);
}

try {
  const parsed = JSON.parse(jsonStr);
  return [{ json: {
    programme: parsed.programme || '',
    module_name: parsed.module_name || '',
    nqf_level: parsed.nqf_level || null,
    assessment_type: parsed.assessment_type || '',
    total_marks: parsed.total_marks || 0,
    questions: parsed.questions || [],
    structure_notes: parsed.structure_notes || [],
    grading_scale: parsed.grading_scale || []
  } }];
} catch (e) {
  return [{ json: { error: 'AI failed to parse the rubric. Please try a clearer PDF.' } }];
}
